const updateAccessByID = `-- name: UpdateAccessByID :exec
UPDATE embedding_cache
SET access_count = access_count + 1,
    last_accessed_at = CURRENT_TIMESTAMP,
    updated_at = CURRENT_TIMESTAMP
WHERE id = ?
`

func (q *Queries) UpdateAccessByID(ctx context.Context, id int64) error {
	_, err := q.db.ExecContext(ctx, updateAccessByID, id)
	return err
}

const updateAccessByIDs = `-- name: UpdateAccessByIDs :exec
UPDATE embedding_cache
SET access_count = access_count + 1,
    last_accessed_at = CURRENT_TIMESTAMP,
    updated_at = CURRENT_TIMESTAMP
WHERE id IN (/*SLICE:ids*/?)
`

func (q *Queries) UpdateAccessByIDs(ctx context.Context, ids []int64) error {
	query := updateAccessByIDs
	var queryParams []interface{}
	if len(ids) > 0 {
		for _, v := range ids {
			queryParams = append(queryParams, v)
		}
		query = strings.Replace(query, "/*SLICE:ids*/?", strings.Repeat(",?", len(ids))[1:], 1)
	} else {
		query = strings.Replace(query, "/*SLICE:ids*/?", "NULL", 1)
	}
	_, err := q.db.ExecContext(ctx, query, queryParams...)
	return err
}

const upsertOCRCache = `-- name: UpsertOCRCache :execresult
INSERT INTO embedding_cache (
  text_hash, text_preview, text_length, embedding, embedding_model,
  vector_dimension, access_count, last_accessed_at, created_at, updated_at
) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
ON DUPLICATE KEY UPDATE
  text_preview = VALUES(text_preview),
  text_length = VALUES(text_length),
  embedding = VALUES(embedding),
  vector_dimension = VALUES(vector_dimension),
  access_count = access_count + 1,
  last_accessed_at = VALUES(last_accessed_at),
  updated_at = VALUES(updated_at)
`

type UpsertOCRCacheParams struct {
	TextHash        string    `json:"text_hash"`
	TextPreview     string    `json:"text_preview"`
	TextLength      int32     `json:"text_length"`
	Embedding       []byte    `json:"embedding"`
	EmbeddingModel  string    `json:"embedding_model"`
	VectorDimension int32     `json:"vector_dimension"`
	AccessCount     int32     `json:"access_count"`
	LastAccessedAt  time.Time `json:"last_accessed_at"`
	CreatedAt       time.Time `json:"created_at"`
	UpdatedAt       time.Time `json:"updated_at"`
}

func (q *Queries) UpsertOCRCache(ctx context.Context, arg UpsertOCRCacheParams) (sql.Result, error) {
	return q.db.ExecContext(ctx, upsertOCRCache,
		arg.TextHash,
		arg.TextPreview,
		arg.TextLength,
		arg.Embedding,
		arg.EmbeddingModel,
		arg.VectorDimension,
		arg.AccessCount,
		arg.LastAccessedAt,
		arg.CreatedAt,
		arg.UpdatedAt,
	)
}
